)
MAIN_CHECKOUT=${MAIN_CHECKOUT_WITH_SENTINEL%?}
if [ -n "$MAIN_CHECKOUT" ] && [ "$(pwd -P)" != "$MAIN_CHECKOUT" ] && [ ! -e .env ] && [ ! -L .env ] && [ -f "$MAIN_CHECKOUT/.env" ]; then
